create table samqa.ar_invoice (
    invoice_id            number not null enable,
    invoice_number        varchar2(30 byte),
    invoice_date          date,
    billing_date          date,
    invoice_due_date      date,
    invoice_posted_date   date,
    cancelled_date        date,
    gl_posted_date        date,
    invoice_type          varchar2(30 byte),
    invoice_amount        number default 0,
    paid_amount           number default 0,
    pending_amount        number default 0,
    void_amount           number default 0,
    entity_id             number,
    entity_type           varchar2(30 byte),
    invoice_term          varchar2(255 byte),
    payment_method        varchar2(255 byte),
    batch_number          varchar2(255 byte),
    note                  varchar2(3200 byte),
    comments              varchar2(3200 byte),
    status                varchar2(255 byte),
    created_by            number,
    creation_date         date default sysdate,
    last_updated_by       number,
    last_update_date      date default sysdate,
    acc_id                number,
    acc_num               varchar2(30 byte),
    bank_acct_id          number,
    auto_pay              varchar2(30 byte),
    rate_plan_id          number,
    last_invoiced_date    date,
    start_date            date,
    end_date              date,
    billing_name          varchar2(255 byte),
    billing_attn          varchar2(255 byte),
    billing_address       varchar2(255 byte),
    billing_city          varchar2(255 byte),
    billing_zip           varchar2(255 byte),
    billing_state         varchar2(255 byte),
    approved_date         date,
    plan_type             varchar2(30 byte),
    mailed_date           date,
    invoice_reason        varchar2(100 byte) default 'FEE',
    division_code         varchar2(255 byte),
    refund_amount         number default 0,
    void_date             date,
    sent_to_collection    varchar2(1 byte) default 'N',
    collection_sent_on    date,
    salesrep_id           number,
    am_id                 number,
    void_reason           varchar2(255 byte),
    main_invoice_id       number,
    cobra_refund_claim_id number,
    charged_to            varchar2(50 byte),
    cc_fee_invoice_id     number
);

alter table samqa.ar_invoice add primary key ( invoice_id )
    using index enable;


